mapper.select:
SELECT id, model_code, model_name, product_line, vendor, category, specifications, config_template, manual_url, image_url, create_time FROM device_model
deleted = 0
AND (model_name LIKE CONCAT('%', #{keyword}, '%') OR model_code LIKE CONCAT('%', #{keyword}, '%') OR vendor LIKE CONCAT('%', #{keyword}, '%'))
AND product_line = #{productLine}
AND category = #{category}
ORDER BY create_time DESC, id DESC

SELECT d.warehouse_id AS warehouseId, w.warehouse_name AS warehouseName, d.model_id AS modelId, m.model_name AS modelName, m.model_code AS modelCode, COUNT(*) AS inStockQty FROM device_instance d LEFT JOIN warehouse w ON w.id = d.warehouse_id AND w.deleted = 0 LEFT JOIN device_model m ON m.id = d.model_id AND m.deleted = 0 WHERE d.deleted = 0 AND d.status = 'IN_FACTORY'
AND d.warehouse_id = #{warehouseId}
AND d.model_id = #{modelId}
GROUP BY d.warehouse_id, w.warehouse_name, d.model_id, m.model_name, m.model_code ORDER BY d.warehouse_id, d.model_id
